import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void shortestBalanced() {
        // [0,1]: one 0 and one 1 → length 2
        assertEquals(2, new Solution().findMaxLength(new int[]{0, 1}));
    }

    @Test
    void oddLengthPartialBalance() {
        // [0,1,0]: best is [0,1] or [1,0], length 2
        assertEquals(2, new Solution().findMaxLength(new int[]{0, 1, 0}));
    }

    @Test
    void entireArrayBalanced() {
        // [0,0,1,1,0,1]: three 0s and three 1s → length 6
        // transformed sums: -1,-2,-1,0,-1,0; runningSum=0 at idx=5 → 5-(-1)=6
        assertEquals(6, new Solution().findMaxLength(new int[]{0, 0, 1, 1, 0, 1}));
    }

    @Test
    void emptyArray() {
        assertEquals(0, new Solution().findMaxLength(new int[]{}));
    }

    @Test
    void allZeros() {
        // [0,0,0]: no 1s → never balanced
        assertEquals(0, new Solution().findMaxLength(new int[]{0, 0, 0}));
    }

    @Test
    void allOnes() {
        // [1,1,1]: no 0s → never balanced
        assertEquals(0, new Solution().findMaxLength(new int[]{1, 1, 1}));
    }

    @Test
    void seedingCritical() {
        // [0,1,0,1]: entire array is balanced → length 4
        // runningSum at idx=3 is 0 → 3-(-1) = 4
        assertEquals(4, new Solution().findMaxLength(new int[]{0, 1, 0, 1}));
    }
}
